noncompliant:
MyClass mc;
//...
mc.~MyClass();  // Noncompliant: explicit destructor call
// Object will be destroyed again when leaving scope

void badFunction() {
  MyClass obj;
  // ... some code
  obj.~MyClass(); // Noncompliant: manual destruction
} // Undefined behavior: destructor called again here

compliant:
void goodFunction() {
  MyClass obj;
  // ... some code
  // Compliant: let destructor be called automatically
} // Destructor called automatically when leaving scope

// Valid exception: placement new scenarios
void* memory = std::malloc(sizeof(MyClass));
MyClass* obj = new(memory) MyClass();
// ... use object
obj->~MyClass(); // Compliant: necessary for placement new
std::free(memory);
